cd /workspace && python3 << 'EOF'
import requests
import json

headers = {"User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"}

# Try the SEC's new full-text data API
# https://www.sec.gov/data/company-index.json
url = "https://www.sec.gov/data/company-index.json"
resp = requests.get(url, headers=headers, timeout=30)
print(f"Status: {resp.status_code}")
if resp.status_code == 200:
    data = resp.json()
    # Search for Hims
    for entry in data:
        if "Hims" in entry.get("name", ""):
            print(f"Found: {entry}")
            break
    else:
        print("Not found, showing first 3 entries:")
        for entry in data[:3]:
            print(f"  {entry}")
else:
    print(f"Response: {resp.text[:500]}")
EOF
